def _read_csv_robust(path, index_col=0, sep=None):
    """
    Read a CSV/TSV that may be encoded in UTF-8, latin-1, cp1252, etc.
    Handles µ, °, and other non-ASCII characters silently.
    Auto-detects tab vs comma delimiter.
    """
    encodings = ['utf-8', 'utf-8-sig', 'latin-1', 'cp1252', 'iso-8859-1']
    
    # Auto-detect separator if not given
    if sep is None:
        try:
            with open(str(path), 'rb') as _f:
                sample = _f.read(4096)
            for enc in encodings:
                try:
                    text = sample.decode(enc)
                    break
                except Exception:
                    text = sample.decode('latin-1')
            sep = '\t' if text.count('\t') > text.count(',') else ','
        except Exception:
            sep = ','

    last_err = None
    for enc in encodings:
        try:
            return pd.read_csv(str(path), index_col=index_col,
                               sep=sep, encoding=enc,
                               on_bad_lines='skip')
        except Exception as e:
            last_err = e
            continue
    raise ValueError(f"Could not read file with any encoding: {last_err}")


