class ThemeManager:
    def __init__(self):
        self.current = 'dark'
        self.pref_file = None
    def init_file(self, workspace):
        self.pref_file = workspace / ".theme"
        if self.pref_file.exists():
            try: self.current = self.pref_file.read_text().strip()
            except: pass
    def toggle(self):
        self.current = 'light' if self.current == 'dark' else 'dark'
        if self.pref_file:
            try: 
                self.pref_file.parent.mkdir(exist_ok=True)
                self.pref_file.write_text(self.current)
            except: pass
        return self.current
    def apply(self, app):
        t = THEMES[self.current]
        p = QPalette()
        p.setColor(QPalette.Window, t['window'])
        p.setColor(QPalette.WindowText, t['text'])
        p.setColor(QPalette.Base, t['base'])
        p.setColor(QPalette.AlternateBase, t['alt_base'])  # Alternating row color
        p.setColor(QPalette.Text, t['text'])  # Text color in input fields
        p.setColor(QPalette.Button, t['button'])
        p.setColor(QPalette.ButtonText, t['text'])  # Button text color
        p.setColor(QPalette.Highlight, t['highlight'])
        p.setColor(QPalette.HighlightedText, QColor(255, 255, 255))  # Selected text always white
        p.setColor(QPalette.PlaceholderText, QColor(128, 140, 150))  # Placeholder text
        app.setPalette(p)

