def _load_persistent_settings():
    """Load settings from the persistent home-directory settings file."""
    if _SETTINGS_FILE.exists():
        try:
            return json.loads(_SETTINGS_FILE.read_text())
        except Exception:
            pass
    return {}

def _save_persistent_setting(key, value):
    """Save a single key/value into the persistent settings file."""
    cfg = _load_persistent_settings()
    cfg[key] = value
    try:
        _SETTINGS_FILE.write_text(json.dumps(cfg, indent=2))
    except Exception:
        pass

