class BackgroundWidget(QWidget):
    """Widget with background image support"""
    def __init__(self, parent=None):
        super().__init__(parent)
        self.background_pixmap = None
        self._setup_background()
    
    def _setup_background(self):
        """Load and setup background image"""
        banner_path = ASSETS_DIR / "banner.png"
        if banner_path.exists():
            self.background_pixmap = QPixmap(str(banner_path))
    
    def paintEvent(self, event):
        """Draw background image with transparency"""
        super().paintEvent(event)
        if self.background_pixmap and not self.background_pixmap.isNull():
            painter = QPainter(self)
            painter.setOpacity(0.08)  # Very subtle transparency
            
            # Scale to fit widget while maintaining aspect ratio
            scaled = self.background_pixmap.scaled(
                self.size(),
                Qt.KeepAspectRatio,
                Qt.SmoothTransformation
            )
            
            # Center the image
            x = (self.width() - scaled.width()) // 2
            y = (self.height() - scaled.height()) // 2
            painter.drawPixmap(x, y, scaled)
            painter.end()

class BannerScrollContainer(QWidget):
    """
    A plain QWidget that paints the banner background on itself.
    Use this as the container inside QScrollArea so the banner shows
    through the scroll area without any transparency bleed-through issues.
    """
    def __init__(self, parent=None):
        super().__init__(parent)
        self.background_pixmap = None
        banner_path = ASSETS_DIR / "banner.png"
        if banner_path.exists():
            self.background_pixmap = QPixmap(str(banner_path))

    def paintEvent(self, event):
        super().paintEvent(event)
        if self.background_pixmap and not self.background_pixmap.isNull():
            painter = QPainter(self)
            painter.setOpacity(0.08)
            scaled = self.background_pixmap.scaled(
                self.size(), Qt.KeepAspectRatio, Qt.SmoothTransformation)
            x = (self.width() - scaled.width()) // 2
            y = (self.height() - scaled.height()) // 2
            painter.drawPixmap(x, y, scaled)
            painter.end()

