def search_ncbi_assemblies(organism_name, max_results=20):
    """Search NCBI Assembly database for organism"""
    try:
        search_term = f'"{organism_name}"[Organism] AND (latest[filter] OR "reference genome"[filter])'
        handle = Entrez.esearch(db="assembly", term=search_term, retmax=max_results)
        record = Entrez.read(handle)
        handle.close()
        
        assembly_ids = record.get("IdList", [])
        if not assembly_ids:
            return []
        
        # Get summaries
        handle = Entrez.esummary(db="assembly", id=",".join(assembly_ids))
        summaries = Entrez.read(handle, validate=False)
        handle.close()
        
        assemblies = []
        for summary in summaries['DocumentSummarySet']['DocumentSummary']:
            assemblies.append({
                'AssemblyAccession': summary.get('AssemblyAccession', ''),
                'AssemblyName': summary.get('AssemblyName', ''),
                'Organism': summary.get('Organism', ''),
                'Status': summary.get('AssemblyStatus', ''),
                'Level': summary.get('AssemblyLevel', ''),
                'FtpPath': summary.get('FtpPath_RefSeq', '') or summary.get('FtpPath_GenBank', '')
            })
        return assemblies
    except Exception as e:
        print(f"Assembly search failed: {e}")
        return []

def detect_accession_type(query):
    """Detect what kind of query the user entered"""
    query = query.strip()
    
    # Assembly: GCF_XXXXXXXXX.X or GCA_XXXXXXXXX.X
    if re.match(r'^GC[FA]_\d{9}\.\d+$', query, re.IGNORECASE):
        return 'assembly', query.upper()
    
    # Chromosome: NC_XXXXXX.X
    if re.match(r'^N[CTWZ]_\d+(\.\d+)?$', query, re.IGNORECASE):
        return 'chromosome', query.upper()
    
    # Simple organism name (no NCBI query operators)
    # Check for whole words to avoid false matches (e.g., "oryza" contains "or")
    if '[' not in query:
        query_lower = query.lower()
        # Use word boundaries to detect NCBI operators as whole words
        has_operators = (
            re.search(r'\band\b', query_lower) or
            re.search(r'\bor\b', query_lower) or
            re.search(r'\bnot\b', query_lower)
        )
        if not has_operators:
            return 'organism', query
    
    # Complex search query
    return 'search', query

