# ── GFF3 / promoter extraction ──
@dataclass
class GeneRecord:
    seqid: str; start: int; end: int
    strand: str; gene_id: str; gene_name: str

def parse_gff3_genes(gff_path, feature_preference="gene"):
    genes, mrnas = [], []
    def parse_attrs(attr_str):
        d = {}
        s = (attr_str or "").strip().strip(";")
        if not s: return d
        parts = [p for p in s.split(";") if p]
        if any("=" in p for p in parts):
            for p in parts:
                if "=" not in p: continue
                k, v = p.split("=", 1)
                d[k.strip()] = v.strip().strip('"')
            return d
        for p in parts:
            p = p.strip()
            if not p: continue
            m = re.match(r'^([A-Za-z0-9_\.\-]+)\s+(.*)$', p)
            if not m: continue
            d[m.group(1).strip()] = m.group(2).strip().strip('"')
        return d
    def pick_first(d, keys):
        for k in keys:
            v = d.get(k)
            if v: return v
        return ""
    with gff_path.open("r", encoding="utf-8", errors="replace") as fh:
        for line in fh:
            if not line or line.startswith("#"): continue
            cols = line.rstrip("\n").split("\t")
            if len(cols) < 9: continue
            seqid, _, ftype, start_s, end_s, _, strand, _, attrs = cols[:9]
            ftype_l = (ftype or "").lower()
            is_gene = ftype_l == "gene"
            is_mrna = ftype_l in ("mrna", "transcript", "rna")
            if not (is_gene or is_mrna): continue
            a = parse_attrs(attrs)
            _id   = pick_first(a, ["ID","gene_id","geneID","locus_tag","transcript_id"])
            _name = pick_first(a, ["Name","gene_name","gene","product","description"])
            _par  = pick_first(a, ["Parent","gene","gene_id"])
            try: s0, e0 = int(start_s), int(end_s)
            except: continue
            rec = GeneRecord(seqid=seqid, start=s0, end=e0,
                             strand=strand if strand in ("+","-") else "+",
                             gene_id=_id or _par or f"{seqid}:{s0}-{e0}",
                             gene_name=_name or _id or _par or "")
            (genes if is_gene else mrnas).append(rec)
    pref = (feature_preference or "gene").lower()
    if pref in ("mrna","transcript"): return mrnas or genes
    return genes or mrnas

def _normalize_gene_id_for_map(raw_id: str) -> str:
    """Strip RefSeq prefixes (gene-, rna-, cds-) and version numbers so IDs
    match across the hits DataFrame and the transcript map."""
    s = str(raw_id).strip()
    for pfx in ("gene-", "rna-", "cds-"):
        if s.lower().startswith(pfx):
            s = s[len(pfx):]
            break
    return s.split(".")[0]


def build_transcript_map_from_gff3(gff_path):
    """Parse a GFF3 (plain or .gz) and return a mapping:
        { normalized_gene_id : {"xm": [XM_xxx, ...], "xp": [XP_xxx, ...]} }

    Works with NCBI RefSeq GFF3 files where:
      gene  features carry  ID=gene-LOC123456
      mRNA  features carry  ID=rna-XM_012345.1  Parent=gene-LOC123456
      CDS   features carry  protein_id=XP_012345.1  Parent=rna-XM_012345.1
    """
    def _attrs(attr_str):
        d = {}
        for p in (attr_str or "").strip().strip(";").split(";"):
            if "=" in p:
                k, v = p.split("=", 1)
                d[k.strip()] = v.strip().strip('"')
        return d

    gff_path = Path(gff_path)
    open_fn = gzip.open if str(gff_path).endswith(".gz") else open

    gene_xm  = {}   # normalized_gene_id -> [XM_, ...]
    gene_xp  = {}   # normalized_gene_id -> [XP_, ...]
    rna_to_gene = {}  # raw rna ID -> normalized_gene_id

    with open_fn(str(gff_path), "rt", encoding="utf-8", errors="replace") as fh:
        for line in fh:
            if not line or line.startswith("#"):
                continue
            cols = line.rstrip("\n").split("\t")
            if len(cols) < 9:
                continue
            ftype = cols[2].lower()
            a = _attrs(cols[8])
            raw_id = a.get("ID", "")

            if ftype == "gene":
                n = _normalize_gene_id_for_map(raw_id)
                gene_xm.setdefault(n, [])
                gene_xp.setdefault(n, [])

            elif ftype in ("mrna", "transcript", "rna"):
                parent_gene = _normalize_gene_id_for_map(a.get("Parent", ""))
                rna_to_gene[raw_id] = parent_gene
                # Extract transcript accession (XM_ / NM_)
                xm_id = ""
                for src in (a.get("Name", ""), _normalize_gene_id_for_map(raw_id)):
                    base = src.split(".")[0]
                    if base.startswith(("XM_", "NM_", "XR_", "NR_")):
                        xm_id = base
                        break
                if parent_gene:
                    gene_xm.setdefault(parent_gene, [])
                    gene_xp.setdefault(parent_gene, [])
                    if xm_id and xm_id not in gene_xm[parent_gene]:
                        gene_xm[parent_gene].append(xm_id)

            elif ftype == "cds":
                protein_id = a.get("protein_id", "")
                if protein_id:
                    xp_id = protein_id.split(".")[0]
                    parent_rna = a.get("Parent", "")
                    gene_id = rna_to_gene.get(parent_rna, "")
                    if gene_id:
                        gene_xp.setdefault(gene_id, [])
                        if xp_id not in gene_xp[gene_id]:
                            gene_xp[gene_id].append(xp_id)

    result = {}
    for k in set(list(gene_xm) + list(gene_xp)):
        result[k] = {"xm": gene_xm.get(k, []), "xp": gene_xp.get(k, [])}
    return result


def extract_promoters(genome_fasta, gff3, out_fasta, out_table,
                      promoter_len=1000, feature_preference="gene"):
    genome_index = SeqIO.index(str(genome_fasta), "fasta")
    genes = parse_gff3_genes(gff3, feature_preference=feature_preference)
    
    # Validate that we have genes
    if not genes:
        raise ValueError(
            f"No gene features found in GFF3 file!\n\n"
            f"The GFF3 file may only contain header lines without actual annotations.\n"
            f"Please ensure you have a proper annotation file with gene/mRNA features.\n\n"
            f"If you used NCBI Fetch, make sure the 'GFF3 annotation' checkbox was ticked\n"
            f"and the conversion completed successfully (check the preview tab)."
        )
    
    rows, written = [], 0
    safe_mkdir(out_fasta.parent); safe_mkdir(out_table.parent)
    with open(out_fasta, "w", encoding="utf-8") as out_f:
        for g in genes:
            seqid = g.seqid
            if seqid not in genome_index:
                alt = None
                for cand in [seqid.replace("Chr",""), f"Chr{seqid}", seqid.replace("chr","Chr")]:
                    if cand in genome_index: alt = cand; break
                if alt is None: continue
                seqid = alt
            seqrec = genome_index[seqid]
            seqlen = len(seqrec.seq)
            if g.strand == "+":
                p_end = g.start - 1; p_start = max(1, p_end - promoter_len + 1)
                if p_end < 1: continue
                prom = seqrec.seq[p_start-1:p_end]
            else:
                p_start = g.end + 1; p_end = min(seqlen, p_start + promoter_len - 1)
                if p_start > seqlen: continue
                prom = seqrec.seq[p_start-1:p_end].reverse_complement()
            header = f"{g.gene_id}|{g.gene_name}|{seqid}:{p_start}-{p_end}({g.strand})"
            out_f.write(f">{header}\n")
            s = str(prom).upper()
            for i in range(0, len(s), 60): out_f.write(s[i:i+60]+"\n")
            rows.append({"gene_id":g.gene_id,"gene_name":g.gene_name,"seqid":seqid,
                "gene_start":g.start,"gene_end":g.end,"strand":g.strand,
                "promoter_start":int(p_start),"promoter_end":int(p_end),
                "promoter_len":int(len(prom)),"promoter_header":header})
            written += 1
    pd.DataFrame(rows).to_csv(out_table, index=False)
    try: genome_index.close()
    except: pass
    return len(genes), written

# ── Motif scanning ──
IUPAC = {"A":"A","C":"C","G":"G","T":"T","U":"T","R":"[AG]","Y":"[CT]","S":"[GC]",
         "W":"[AT]","K":"[GT]","M":"[AC]","B":"[CGT]","D":"[AGT]","H":"[ACT]","V":"[ACG]","N":"[ACGT]"}

def iupac_to_regex(seq):
    return "".join("." if ch=="." else IUPAC.get(ch, re.escape(ch)) for ch in seq.upper())

def parse_motif_lines(text):
    motifs = []
    for raw in (text or "").splitlines():
        line = raw.strip()
        if not line or line.startswith("#"): continue
        name = pat = None
        if "\t" in line:
            parts = line.split("\t")
            if len(parts) >= 2: name, pat = parts[0].strip(), parts[1].strip()
        elif ":" in line:
            parts = line.split(":", 1)
            name, pat = parts[0].strip(), parts[1].strip()
        else:
            pat = line; name = f"motif_{len(motifs)+1}"
        if pat: motifs.append((name or f"motif_{len(motifs)+1}", pat.replace(" ","")))
    return motifs

def record_to_gene_id(record_id):
    if "|" in record_id:
        parts = record_id.split("|")
        return parts[0].strip(), (parts[1].strip() if len(parts) > 1 else parts[0].strip())
    tok = record_id.split()[0]
    return tok, tok

def scan_fasta_for_motifs(fasta_path, motifs, treat_as_iupac=True,
                          allow_overlaps=True, search_revcomp=True, context_bp=0):
    rows = []
    for name, pat in motifs:
        rex = iupac_to_regex(pat) if treat_as_iupac else pat
        cre = re.compile(f"(?=({rex}))" if allow_overlaps else rex, flags=re.IGNORECASE)
        rc_cre = rc_pat = None
        if search_revcomp and treat_as_iupac:
            try:
                rc_pat = str(Seq(pat.upper().replace("U","T")).reverse_complement())
                rc_rex = iupac_to_regex(rc_pat)
                rc_cre = re.compile(f"(?=({rc_rex}))" if allow_overlaps else rc_rex, flags=re.IGNORECASE)
            except: rc_cre = None
        for rec in SeqIO.parse(str(fasta_path), "fasta"):
            seq = str(rec.seq).upper()
            seq_len = len(seq)   # true promoter length for significance test
            gene_id, gene_name = record_to_gene_id(rec.id)
            for m in cre.finditer(seq):
                if allow_overlaps: start = m.start(1)+1; match_seq = m.group(1); end = start+len(match_seq)-1
                else: start = m.start()+1; match_seq = m.group(0); end = m.end()
                rows.append({"record_id":rec.id,"gene_id":gene_id,"gene_name":gene_name,
                    "motif_name":name,"motif_pattern":pat,"strand":"+",
                    "start_1based":start,"end_1based":end,"matched_seq":match_seq,
                    "seq_len":seq_len,
                    "context_up":seq[max(0,start-1-context_bp):start-1] if context_bp else "",
                    "context_down":seq[end:min(len(seq),end+context_bp)] if context_bp else ""})
            if rc_cre and rc_pat:
                for m in rc_cre.finditer(seq):
                    if allow_overlaps: start = m.start(1)+1; match_seq = m.group(1); end = start+len(match_seq)-1
                    else: start = m.start()+1; match_seq = m.group(0); end = m.end()
                    rows.append({"record_id":rec.id,"gene_id":gene_id,"gene_name":gene_name,
                        "motif_name":name+"_RC","motif_pattern":rc_pat,"strand":"-",
                        "start_1based":start,"end_1based":end,"matched_seq":match_seq,
                        "seq_len":seq_len,
                        "context_up":seq[max(0,start-1-context_bp):start-1] if context_bp else "",
                        "context_down":seq[end:min(len(seq),end+context_bp)] if context_bp else ""})
    df = pd.DataFrame(rows)
    
    if not df.empty:
        if CHROMOSOME_UTILS_AVAILABLE:
            df = add_chromosome_column(df)
        df = df.sort_values(["gene_id","motif_name","start_1based"]).reset_index(drop=True)
        # Add p-value / significance
        try:
            df = add_pvalues_to_hits(df)
        except Exception:
            pass   # scipy not available — skip silently
    
    return df

# ── Statistical significance (p-value) for motif hits ────────────────────
def _motif_match_prob(motif_pattern: str, bg_gc: float = 0.5) -> float:
    """
    Compute the probability that a random nucleotide matches one position
    of a IUPAC motif, given a GC background frequency.
    Returns the probability that a random string of the motif's length
    matches the whole motif (product across positions).
    """
    bg = {"A": (1-bg_gc)/2, "C": bg_gc/2, "G": bg_gc/2, "T": (1-bg_gc)/2}
    IUPAC_BASES = {
        "A":["A"],"C":["C"],"G":["G"],"T":["T"],
        "R":["A","G"],"Y":["C","T"],"S":["G","C"],"W":["A","T"],
        "K":["G","T"],"M":["A","C"],"B":["C","G","T"],"D":["A","G","T"],
        "H":["A","C","T"],"V":["A","C","G"],"N":["A","C","G","T"],
    }
    prob = 1.0
    for base in motif_pattern.upper():
        bases = IUPAC_BASES.get(base, ["A","C","G","T"])
        prob *= sum(bg.get(b, 0.25) for b in bases)
    return prob


def add_pvalues_to_hits(df: "pd.DataFrame") -> "pd.DataFrame":
    """
    Add p_value, p_value_adj (FDR Benjamini-Hochberg), neg_log10_p, and significance columns.
    Uses true promoter length (seq_len column) and BH-FDR correction.
    """
    from scipy.stats import binom as _binom
    import numpy as np

    if df.empty:
        for col in ["p_value", "p_value_adj", "neg_log10_p", "significance"]:
            df[col] = None
        return df

    # Use real seq_len if available; fallback to max-hit-pos (underestimates — old bug)
    if "seq_len" in df.columns:
        gene_len = df.groupby("record_id")["seq_len"].max().to_dict()
    else:
        gene_len = df.groupby("record_id")["end_1based"].max().to_dict()

    hit_counts = (df.groupby(["record_id", "motif_name"])
                    .size().reset_index(name="hit_count"))

    if "matched_seq" in df.columns:
        all_seq = "".join(df["matched_seq"].dropna().astype(str)).upper()
        gc = (all_seq.count("G") + all_seq.count("C")) / max(len(all_seq), 1)
        bg_gc = max(0.1, min(0.9, gc))
    else:
        bg_gc = 0.5

    motif_prob = {}
    for motif_name in hit_counts["motif_name"].unique():
        pat_rows = df[df["motif_name"] == motif_name]["motif_pattern"]
        motif_prob[motif_name] = _motif_match_prob(pat_rows.iloc[0], bg_gc) if len(pat_rows) else 0.25**6

    pval_map = {}
    for _, row in hit_counts.iterrows():
        gene    = row["record_id"]
        motif   = row["motif_name"]
        k       = int(row["hit_count"])
        L       = int(gene_len.get(gene, 2000))
        pat_len = len(df.loc[(df["record_id"] == gene) & (df["motif_name"] == motif), "motif_pattern"].iloc[0])
        n_pos    = max(1, L - pat_len + 1)
        p_single = motif_prob.get(motif, 0.25**pat_len)
        pval_map[(gene, motif)] = max(float(1.0 - _binom.cdf(k - 1, n_pos, p_single)), 1e-300)

    df = df.copy()
    df["p_value"] = df.apply(lambda r: pval_map.get((r["record_id"], r["motif_name"]), 1.0), axis=1)

    # Benjamini-Hochberg FDR
    n_tests      = len(pval_map)
    keys         = list(pval_map.keys())
    unique_pvals = np.array([pval_map[k] for k in keys])
    order        = np.argsort(unique_pvals)
    ranks        = np.empty_like(order); ranks[order] = np.arange(1, n_tests + 1)
    bh_adj       = np.minimum(1.0, unique_pvals * n_tests / ranks)
    for i in range(n_tests - 2, -1, -1):
        bh_adj[order[i]] = min(bh_adj[order[i]], bh_adj[order[i + 1]])
    adj_map = {k: v for k, v in zip(keys, bh_adj)}

    df["p_value_adj"] = df.apply(lambda r: adj_map.get((r["record_id"], r["motif_name"]), 1.0), axis=1)
    df["neg_log10_p"] = (-np.log10(df["p_value"])).round(2)

    def _stars(p):
        if p <= 1e-10: return "★★★★★"
        if p <= 1e-6:  return "★★★★"
        if p <= 1e-4:  return "★★★"
        if p <= 0.01:  return "★★"
        if p <= 0.05:  return "★"
        return "ns"

    df["significance"] = df["p_value_adj"].apply(_stars)
    return df


# ── Logo rendering ──
IUPAC_MAP = {
    "A":{"A":1,"C":0,"G":0,"T":0},"C":{"A":0,"C":1,"G":0,"T":0},
    "G":{"A":0,"C":0,"G":1,"T":0},"T":{"A":0,"C":0,"G":0,"T":1},
    "R":{"A":.5,"C":0,"G":.5,"T":0},"Y":{"A":0,"C":.5,"G":0,"T":.5},
    "S":{"A":0,"C":.5,"G":.5,"T":0},"W":{"A":.5,"C":0,"G":0,"T":.5},
    "K":{"A":0,"C":0,"G":.5,"T":.5},"M":{"A":.5,"C":.5,"G":0,"T":0},
    "B":{"A":0,"C":1/3,"G":1/3,"T":1/3},"D":{"A":1/3,"C":0,"G":1/3,"T":1/3},
    "H":{"A":1/3,"C":1/3,"G":0,"T":1/3},"V":{"A":1/3,"C":1/3,"G":1/3,"T":0},
    "N":{"A":.25,"C":.25,"G":.25,"T":.25},
}

def probs_from_iupac_motif(motif):
    rows = []
    for base in motif.upper():
        if base not in IUPAC_MAP: raise ValueError(f"Invalid IUPAC base: {base}")
        rows.append(IUPAC_MAP[base])
    return pd.DataFrame(rows)

def probs_from_sequences(seqs):
    if not seqs: raise ValueError("No sequences.")
    seqs = [s.upper() for s in seqs if s]
    length = len(seqs[0])
    for s in seqs:
        if len(s) != length: raise ValueError("All sequences must be the same length.")
    counts = {"A":[0]*length,"C":[0]*length,"G":[0]*length,"T":[0]*length}
    for s in seqs:
        for i, base in enumerate(s):
            if base in counts: counts[base][i] += 1
    df = pd.DataFrame(counts)
    df = df.div(df.sum(axis=1), axis=0)
    return df

def probs_to_bits(df):
    with np.errstate(divide="ignore", invalid="ignore"):
        ic = df * np.log2(df / 0.25)
        ic = ic.replace([np.inf, -np.inf], 0).fillna(0)
    return ic

def render_logo_to_png(df, scale="bits", width_mode="Medium"):
    if scale == "bits": plot_df = probs_to_bits(df); ylabel = "Information (bits)"; ymax = 2.1
    else: plot_df = df; ylabel = "Frequency"; ymax = 1.05
    wmap = {"Compact":max(3,df.shape[0]*.35),"Medium":max(4.5,df.shape[0]*.5),"Wide":max(6.5,df.shape[0]*.7)}
    fig, ax = plt.subplots(figsize=(wmap.get(width_mode, 5), 3))
    logomaker.Logo(plot_df, ax=ax, stack_order="big_on_top", fade_below=0, shade_below=0)
    ax.set_ylabel(ylabel); ax.set_xlabel("Position"); ax.set_ylim(0, ymax)
    ax.set_xticks(range(plot_df.shape[0])); ax.set_xticklabels(range(1, plot_df.shape[0]+1))
    ax.spines["top"].set_visible(False); ax.spines["right"].set_visible(False)
    plt.tight_layout()
    buf = io.BytesIO(); fig.savefig(buf, dpi=150, bbox_inches="tight"); plt.close(fig)
    return buf.getvalue()

# ── OLD NCBI helpers (PRESERVED for backward compatibility) ──────
def ncbi_search(query, max_results=25):
    """Return raw GI ID strings from esearch."""
    handle = Entrez.esearch(db="nucleotide", term=query, retmax=max_results)
    record = Entrez.read(handle); handle.close()
    return record.get("IdList", [])

def ncbi_summary(ids):
    """Fetch summary metadata using GI IDs."""
    if not ids: return pd.DataFrame()
    handle = Entrez.esummary(db="nucleotide", id=",".join(ids))
    records = Entrez.read(handle); handle.close()
    return pd.DataFrame([{
        "GI":         r.get("Id", ""),
        "Accession":  r.get("Accession", ""),
        "Title":      r.get("Title", ""),
        "Organism":   r.get("Organism", ""),
        "Length_bp":  int(r.get("Length", 0))
    } for r in records])

def ncbi_fetch_fasta(ids):
    """Fetch FASTA using GI IDs (not accessions) with batch processing."""
    if not ids: return ""
    
    import time
    
    id_list = list(ids) if not isinstance(ids, list) else ids
    batch_size = 100
    all_fasta = []
    
    for i in range(0, len(id_list), batch_size):
        batch = id_list[i:i+batch_size]
        if i > 0: time.sleep(0.4)
        
        try:
            handle = Entrez.efetch(
                db="nucleotide", 
                id=",".join(str(x) for x in batch),
                rettype="fasta", 
                retmode="text"
            )
            text = handle.read()
            handle.close()
            if text: all_fasta.append(text)
        except Exception as e:
            print(f"Warning: Failed to fetch FASTA batch {i//batch_size + 1}: {e}")
            continue
    
    return "".join(all_fasta)

# ── Coexpression helpers ──
def generate_example_expression_data(n_genes=100, n_samples=12, output_path=None):
    """Generate realistic example gene expression data for testing
    
    Creates synthetic expression data with:
    - Realistic gene IDs (AT1G00010 Arabidopsis format)
    - Biologically plausible expression values
    - Co-expressed gene modules (5 modules with different patterns)
    - Realistic noise and variation
    
    Args:
        n_genes: Number of genes (default 100 for quick demo)
        n_samples: Number of samples/conditions (default 12)
        output_path: Where to save CSV (default: workspace/expression/example_expression_data.csv)
    
    Returns:
        Path to saved file
    """
    # Generate gene IDs (Arabidopsis-style: AT1G00010, AT1G00020, etc.)
    gene_ids = [f"AT{i//20000 + 1}G{str(i%20000).zfill(5)}" for i in range(10000, 10000 + n_genes)]
    
    # Sample names (control, stress, heat conditions with replicates)
    conditions = ['control', 'stress', 'heat'] * 4
    sample_names = [f"{cond}_rep{i%4+1}" for i, cond in enumerate(conditions[:n_samples])]
    
    # Create base expression levels (log-normal distribution mimics real gene expression)
    np.random.seed(42)  # Reproducible results
    base_expression = np.random.lognormal(mean=5, sigma=2, size=n_genes)
    
    # Create 5 co-expressed modules with different response patterns
    n_modules = 5
    module_size = n_genes // n_modules
    expression_matrix = np.zeros((n_genes, n_samples))
    
    for i in range(n_genes):
        module = i // module_size
        
        # Each module has a characteristic response pattern
        if module == 0:  # Stress-responsive genes (upregulated under stress)
            pattern = [1, 1, 1, 1, 3, 3, 3, 3, 2, 2, 2, 2][:n_samples]
        elif module == 1:  # Heat-responsive genes (upregulated under heat)
            pattern = [1, 1, 1, 1, 1, 1, 1, 1, 4, 4, 4, 4][:n_samples]
        elif module == 2:  # Constitutive genes (stable expression)
            pattern = [2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2][:n_samples]
        elif module == 3:  # Repressed under stress
            pattern = [3, 3, 3, 3, 1, 1, 1, 1, 1, 1, 1, 1][:n_samples]
        else:  # Random/noisy genes (variable expression)
            pattern = np.random.uniform(0.5, 3, n_samples)
        
        # Generate expression: base_level × pattern + biological noise
        expression_matrix[i, :] = base_expression[i] * np.array(pattern) + \
                                  np.random.normal(0, base_expression[i] * 0.1, n_samples)
    
    # Ensure all values are positive (can't have negative expression)
    expression_matrix = np.maximum(expression_matrix, 0.1)
    
    # Create DataFrame with genes as rows, samples as columns
    expr_df = pd.DataFrame(expression_matrix, index=gene_ids, columns=sample_names)
    
    # Save to file
    if output_path is None:
        output_path = EXPR_DIR / "example_expression_data.csv"
    
    safe_mkdir(output_path.parent)
    expr_df.to_csv(output_path)
    
    print(f"✓ Generated example expression data: {output_path}")
    print(f"  Genes: {n_genes}, Samples: {n_samples}")
    print(f"  Modules: 5 (stress, heat, constitutive, repressed, random)")
    
    return output_path

def calculate_correlation_matrix(expr_df, method='pearson'):
    """
    Calculate gene-gene correlation matrix
    
    Input: expr_df with rows=genes, columns=samples
    Output: correlation matrix with genes x genes
    
    CRITICAL: We transpose so correlations are computed BETWEEN GENES,
    not between samples/tissues!
    """
    return expr_df.T.corr(method=method)

def detect_coexpression_modules(corr_matrix, threshold=0.7, method='louvain'):
    if not NETWORKX_AVAILABLE:
        raise ImportError("NetworkX not installed.  Run:  pip install networkx")
    G = nx.Graph()
    genes = corr_matrix.columns.tolist()
    G.add_nodes_from(genes)
    for i, g1 in enumerate(genes):
        for j, g2 in enumerate(genes):
            if i < j and abs(corr_matrix.iloc[i, j]) >= threshold:
                G.add_edge(g1, g2, weight=abs(corr_matrix.iloc[i, j]))
    if method == 'louvain' and LOUVAIN_AVAILABLE:
        communities = community_louvain.best_partition(G)
    else:
        communities = {}
        for i, comp in enumerate(nx.connected_components(G)):
            for node in comp: communities[node] = i
    return communities, G

def normalize_expression_data(df, method='log2'):
    if method in ('tpm', 'log2'):
        return np.log2(df + 1)
    elif method == 'zscore':
        return (df - df.mean()) / df.std()
    elif method == 'quantile':
        rank_mean = df.stack().groupby(df.rank(method='first').stack().astype(int)).mean()
        return df.rank(method='min').stack().astype(int).map(rank_mean).unstack()
    return df

def render_correlation_heatmap(corr_matrix, output_path=None):
    fig, ax = plt.subplots(figsize=(12, 10))
    sns.heatmap(corr_matrix, cmap='RdBu_r', center=0, square=True,
                linewidths=0, cbar_kws={"shrink": 0.8}, vmin=-1, vmax=1)
    ax.set_title("Gene-Gene Correlation Matrix", fontsize=14, fontweight='bold')
    plt.tight_layout()
    if output_path:
        fig.savefig(output_path, dpi=150, bbox_inches='tight'); plt.close(fig); return None
    buf = io.BytesIO()
    fig.savefig(buf, dpi=150, bbox_inches='tight'); plt.close(fig)
    return buf.getvalue()

def render_network_plot(G, communities, output_path=None, hide_isolated=False, 
                       layout_type='spring', node_size=300, font_size=8):
    """
    Render network plot with options for isolated nodes and layout
    
    Parameters:
    -----------
    G : networkx.Graph
    communities : dict - {node: community_id}
    output_path : str - save path (PNG or SVG based on extension)
    hide_isolated : bool - if True, hide nodes with no connections
    layout_type : str - 'spring', 'circular', 'kamada_kawai', 'spectral'
    node_size : int - size of nodes
    font_size : int - label font size
    """
    if not NETWORKX_AVAILABLE: return None
    
    # Filter isolated nodes if requested
    if hide_isolated:
        # Remove nodes with degree 0 (no connections)
        nodes_to_keep = [n for n in G.nodes() if G.degree(n) > 0]
        G_filtered = G.subgraph(nodes_to_keep).copy()
    else:
        G_filtered = G
    
    if len(G_filtered.nodes()) == 0:
        return None
    
    # Choose layout algorithm
    if layout_type == 'spring':
        pos = nx.spring_layout(G_filtered, k=0.5, iterations=50, seed=42)
    elif layout_type == 'circular':
        pos = nx.circular_layout(G_filtered)
    elif layout_type == 'kamada_kawai':
        pos = nx.kamada_kawai_layout(G_filtered)
    elif layout_type == 'spectral':
        pos = nx.spectral_layout(G_filtered)
    else:
        pos = nx.spring_layout(G_filtered, k=0.5, iterations=50, seed=42)
    
    # Create figure
    fig, ax = plt.subplots(figsize=(16, 14))
    
    # Color by communities
    unique_comms = set(communities.values())
    colors = plt.cm.Set3(np.linspace(0, 1, max(len(unique_comms), 1)))
    color_map = {c: colors[i] for i, c in enumerate(unique_comms)}
    node_colors = [color_map[communities.get(n, 0)] for n in G_filtered.nodes()]
    
    # Draw network
    nx.draw_networkx_nodes(G_filtered, pos, node_color=node_colors, 
                          node_size=node_size, alpha=0.8, ax=ax)
    nx.draw_networkx_edges(G_filtered, pos, alpha=0.3, width=0.5, ax=ax)
    nx.draw_networkx_labels(G_filtered, pos, font_size=font_size, ax=ax)
    
    # Add statistics to title
    n_nodes = len(G_filtered.nodes())
    n_edges = len(G_filtered.edges())
    n_communities = len(unique_comms)
    title = f"Coexpression Network\n{n_nodes} genes, {n_edges} edges, {n_communities} modules"
    if hide_isolated:
        title += "\n(Isolated nodes hidden)"
    ax.set_title(title, fontsize=14, fontweight='bold')
    
    ax.axis('off')
    plt.tight_layout()
    
    # Save based on file extension
    if output_path:
        ext = output_path.lower().split('.')[-1]
        if ext == 'svg':
            fig.savefig(output_path, format='svg', bbox_inches='tight')
        else:
            fig.savefig(output_path, dpi=150, bbox_inches='tight')
        plt.close(fig)
        return None
    
    # Return PNG bytes
    buf = io.BytesIO()
    fig.savefig(buf, format='png', dpi=150, bbox_inches='tight')
    plt.close(fig)
    buf.seek(0)
    return buf.getvalue()

