# ═══════════════════════════════════════════════════════════
# WORKER THREAD
# ═══════════════════════════════════════════════════════════
class WorkerThread(QThread):
    finished = pyqtSignal(object)
    error    = pyqtSignal(str)
    def __init__(self, fn, *args, **kwargs):
        super().__init__()
        self._fn = fn; self._args = args; self._kwargs = kwargs
    def run(self):
        try:  self.finished.emit(self._fn(*self._args, **self._kwargs))
        except Exception as e: self.error.emit(str(e))

class DownloadWorkerThread(QThread):
    """Worker thread for downloads with progress reporting and cancellation."""
    finished = pyqtSignal(object)
    error    = pyqtSignal(str)
    progress = pyqtSignal(int, int, str)  # downloaded, total, file_label

    def __init__(self, fn, *args, **kwargs):
        super().__init__()
        self._fn = fn; self._args = args; self._kwargs = kwargs
        self._cancelled = False

    def cancel(self):
        self._cancelled = True

    def is_cancelled(self):
        return self._cancelled

    def _on_progress(self, downloaded, total, label):
        self.progress.emit(downloaded, total, label)

    def run(self):
        try:
            result = self._fn(*self._args, progress_callback=self._on_progress,
                              cancel_flag=self.is_cancelled, **self._kwargs)
            if not self._cancelled:
                self.finished.emit(result)
            else:
                self.finished.emit(("", "", "Download cancelled by user"))
        except Exception as e:
            self.error.emit(str(e))

# ─── GUI helpers ───
def create_help_button(help_text):
    """Create a small ? help button with tooltip"""
    btn = QPushButton("?")
    btn.setFixedSize(22, 22)
    btn.setStyleSheet("font-weight: bold; font-size: 10px;")
    btn.setToolTip(help_text)
    btn.clicked.connect(lambda: QMessageBox.information(
        None, "Help", help_text
    ))
    return btn

def df_to_table(df, table):
    table.setRowCount(len(df)); table.setColumnCount(len(df.columns))
    table.setHorizontalHeaderLabels(list(df.columns))
    for r, row in df.iterrows():
        for c, val in enumerate(row):
            item = QTableWidgetItem(str(val))
            item.setFlags(item.flags() & ~Qt.ItemIsEditable)
            table.setItem(r, c, item)
    table.horizontalHeader().setSectionResizeMode(QHeaderView.ResizeToContents)

def pick_file(parent, title, folder, filt):
    path, _ = QFileDialog.getOpenFileName(parent, title, str(folder), filt)
    return path

