    # ══ NEW: Smart Search Logic ══
    def _do_search(self):
        query = self.query_edit.text().strip()
        if not query:
            QMessageBox.warning(self, "Cis-GS", "Enter a query")
            return
        
        # Auto-detect or use selected mode
        mode = self.mode_combo.currentText()
        
        if "Auto-detect" in mode:
            query_type, value = detect_accession_type(query)
        elif "Assembly" in mode:
            query_type, value = 'assembly', query
        elif "Organism" in mode:
            query_type, value = 'organism', query
        elif "Chromosome" in mode:
            query_type, value = 'chromosome', query
        else:  # Legacy
            self._do_legacy_search()
            return
        
        self.info_lbl.setText(f"🔍 Detected: {query_type.upper()} → {value}")
        
        # Route to appropriate handler
        if query_type == 'assembly':
            self._search_assembly_direct(value)
        elif query_type == 'organism':
            self._search_organism_assemblies(value)
        elif query_type == 'chromosome':
            self._handle_chromosome_query(value)
        else:
            self._do_legacy_search()

    def _search_assembly_direct(self, assembly_acc):
        """User entered assembly ID directly"""
        self.progress.setVisible(True)
        self.dna_loader.start()
        self.search_btn.setEnabled(False)
        self.status_lbl.setText("Verifying assembly...")
        
        def _search():
            return search_ncbi_assemblies(assembly_acc, max_results=1)
        
        self._worker = WorkerThread(_search)
        self._worker.finished.connect(self._on_assembly_search_done)
        self._worker.error.connect(self._on_error)
        self._worker.start()

    def _search_organism_assemblies(self, organism):
        """User entered organism name"""
        self.progress.setVisible(True)
        self.search_btn.setEnabled(False)
        self.status_lbl.setText(f"Searching assemblies for {organism}...")
        
        def _search():
            return search_ncbi_assemblies(organism, max_results=20)
        
        self._worker = WorkerThread(_search)
        self._worker.finished.connect(self._on_assembly_search_done)
        self._worker.error.connect(self._on_error)
        self._worker.start()

    def _handle_chromosome_query(self, chr_acc):
        """User entered chromosome - suggest assembly"""
        suggested = get_assembly_from_chromosome(chr_acc)
        
        if suggested:
            msg = (
                f"ℹ️ Chromosome Accession Detected\n\n"
                f"You entered: {chr_acc}\n\n"
                f"For complete genome + GFF3 annotation, use:\n"
                f"👉 {suggested}\n\n"
                f"Would you like to use the assembly instead?"
            )
            
            reply = QMessageBox.question(
                self,
                "Use Assembly?",
                msg,
                QMessageBox.Yes | QMessageBox.No
            )
            
            if reply == QMessageBox.Yes:
                self.query_edit.setText(suggested)
                self._search_assembly_direct(suggested)
            else:
                # Fall back to legacy search
                self._do_legacy_search()
        else:
            QMessageBox.information(
                self,
                "Unknown Chromosome",
                f"No assembly mapping found for {chr_acc}.\n\n"
                f"Using legacy nucleotide search instead."
            )
            self._do_legacy_search()

    def _on_assembly_search_done(self, assemblies):
        """Handle assembly search results"""
        self.progress.setVisible(False)
        self.dna_loader.stop()
        self.search_btn.setEnabled(True)
        
        if not assemblies:
            self.status_lbl.setText("❌ No assemblies found")
            QMessageBox.warning(
                self,
                "No Results",
                "No assemblies found.\n\n"
                "Try:\n"
                "• Check spelling\n"
                "• Use scientific name\n"
                "• Search NCBI Genome manually"
            )
            return
        
        self._assemblies = assemblies
        self._assemblies_df = pd.DataFrame(assemblies)
        
        # Display in table
        display_df = self._assemblies_df[[
            'AssemblyAccession', 'AssemblyName', 'Organism', 'Status', 'Level'
        ]]
        df_to_table(display_df, self.table)
        
        self.status_lbl.setText(f"✓ Found {len(assemblies)} assembly/assemblies")
        
        # If only one result, auto-select it
        if len(assemblies) == 1:
            self._selected_assembly = assemblies[0]
            self.selected_asm_lbl.setText(
                f"{assemblies[0]['AssemblyAccession']} - {assemblies[0]['AssemblyName']}"
            )
            self.dl_group.setVisible(True)
            QMessageBox.information(
                self,
                "Assembly Found",
                f"Found: {assemblies[0]['AssemblyAccession']}\n"
                f"Name: {assemblies[0]['AssemblyName']}\n"
                f"Organism: {assemblies[0]['Organism']}\n\n"
                f"Click 'Download Files' to get FASTA + GFF3!"
            )
        else:
            self.dl_group.setVisible(True)
            QMessageBox.information(
                self,
                "Multiple Assemblies",
                f"Found {len(assemblies)} assemblies.\n\n"
                f"Click a row to select one, then download.\n\n"
                f"💡 Tip: Choose 'Reference' or 'Complete' assemblies"
            )

    def _on_table_select(self, row, col):
        """User clicked a row in the assemblies table"""
        if row < len(self._assemblies):
            self._selected_assembly = self._assemblies[row]
            self.selected_asm_lbl.setText(
                f"{self._selected_assembly['AssemblyAccession']} - "
                f"{self._selected_assembly['AssemblyName']}"
            )
            self.status_lbl.setText(f"Selected: {self._selected_assembly['AssemblyAccession']}")

    def _do_download(self):
        """Download files from assembly FTP with progress and cancel support"""
        if not self._selected_assembly:
            QMessageBox.warning(self, "Cis-GS", "Select an assembly first")
            return

        assembly_acc = self._selected_assembly['AssemblyAccession']
        download_fasta = self.fetch_fasta_cb.isChecked()
        download_gff = self.fetch_gff_cb.isChecked()

        if not download_fasta and not download_gff:
            QMessageBox.warning(self, "Cis-GS", "Select at least one file type")
            return

        self.dl_progress.setVisible(True)
        self.dl_progress.setValue(0)
        self.dl_progress.setFormat("Connecting...")
        self.dl_status_lbl.setVisible(True)
        self.dl_status_lbl.setText(f"Downloading from {assembly_acc}...")
        self.download_btn.setEnabled(False)
        self.stop_btn.setVisible(True)
        self.dna_loader.start()
        self.status_lbl.setText(f"Downloading from {assembly_acc}...")

        self._dl_worker = DownloadWorkerThread(
            download_assembly_files, assembly_acc, download_fasta, download_gff
        )
        self._dl_worker.progress.connect(self._on_dl_progress)
        self._dl_worker.finished.connect(self._on_download_done)
        self._dl_worker.error.connect(self._on_error)
        self._dl_worker.start()

    def _on_dl_progress(self, downloaded, total, label):
        """Update download progress bar with real-time info"""
        if total > 0:
            pct = int(downloaded * 100 / total)
            self.dl_progress.setRange(0, 100)
            self.dl_progress.setValue(pct)
            dl_mb = downloaded / (1024 * 1024)
            total_mb = total / (1024 * 1024)
            self.dl_progress.setFormat(f"{label}: {dl_mb:.1f} / {total_mb:.1f} MB ({pct}%)")
            self.dl_status_lbl.setText(f"Downloading {label}... {dl_mb:.1f} / {total_mb:.1f} MB")
        else:
            # Unknown total size — show downloaded amount only
            dl_mb = downloaded / (1024 * 1024)
            self.dl_progress.setRange(0, 0)  # indeterminate
            self.dl_status_lbl.setText(f"Downloading {label}... {dl_mb:.1f} MB downloaded")

    def _do_cancel_download(self):
        """Cancel the ongoing download"""
        if hasattr(self, '_dl_worker') and self._dl_worker and self._dl_worker.isRunning():
            self._dl_worker.cancel()
            self.dl_status_lbl.setText("Cancelling download...")
            self.stop_btn.setEnabled(False)

    def _on_download_done(self, result):
        """Handle download completion"""
        self.progress.setVisible(False)
        self.dl_progress.setVisible(False)
        self.dl_status_lbl.setVisible(False)
        self.stop_btn.setVisible(False)
        self.stop_btn.setEnabled(True)
        self.dna_loader.stop()
        self.download_btn.setEnabled(True)
        
        fasta_text, gff_text, message = result
        self._fasta_text = fasta_text
        self._gff_text = gff_text
        
        # Show previews
        has_data = False
        if fasta_text:
            preview = fasta_text[:2000] + ("..." if len(fasta_text) > 2000 else "")
            self.preview_fasta.setPlainText(preview)
            self.preview_fasta_logo.setVisible(False)
            self.preview_fasta.setVisible(True)
            has_data = True
        
        if gff_text:
            preview = gff_text[:2000] + ("..." if len(gff_text) > 2000 else "")
            self.preview_gff.setPlainText(preview)
            self.preview_gff_logo.setVisible(False)
            self.preview_gff.setVisible(True)
            has_data = True
        
        if has_data:
            self.preview_tabs.setVisible(True)
            self.save_btn.setVisible(True)
            self.status_lbl.setText(message)
            QMessageBox.information(self, "Download Complete", message)
        else:
            self.status_lbl.setText("Download failed - see message")
            QMessageBox.critical(self, "Download Failed", message)

    def _open_ftp(self):
        """Open assembly FTP folder in browser"""
        if not self._selected_assembly:
            QMessageBox.warning(self, "Cis-GS", "Select an assembly first")
            return
        
        ftp_path = self._selected_assembly.get('FtpPath', '')
        if ftp_path:
            # Convert to HTTPS
            url = ftp_path.replace('ftp://', 'https://')
            QDesktopServices.openUrl(QUrl(url))
        else:
            QMessageBox.information(self, "No FTP", "No FTP path available")

    def _do_save(self):
        """Save downloaded files to workspace"""
        if not self._fasta_text and not self._gff_text:
            QMessageBox.warning(self, "Cis-GS", "Download files first")
            return
        
        saved = []
        if self._fasta_text:
            dest = unique_path(GENOMES_DIR / self.fname_edit.text().strip())
            safe_mkdir(dest.parent)
            dest.write_text(self._fasta_text, encoding="utf-8")
            self.fname_edit.setText(dest.name)   # reflect actual saved name
            saved.append(str(dest))

        if self._gff_text:
            dest = unique_path(ANNOT_DIR / self.gff_fname_edit.text().strip())
            safe_mkdir(dest.parent)
            dest.write_text(self._gff_text, encoding="utf-8")
            self.gff_fname_edit.setText(dest.name)   # reflect actual saved name
            saved.append(str(dest))
        
        self.status_lbl.setText(f"Saved {len(saved)} file(s)")
        QMessageBox.information(self, "Saved", "Saved:\n" + "\n".join(saved))

    def _do_legacy_search(self):
        """Fall back to old nucleotide search"""
        query = self.query_edit.text().strip()
        self.progress.setVisible(True)
        self.search_btn.setEnabled(False)
        self.status_lbl.setText("Searching nucleotide database...")
        self.info_lbl.setText("🔍 Using legacy nucleotide search")
        
        def _s():
            ids = ncbi_search(query, 25)
            return {"ids": ids, "summary": ncbi_summary(ids) if ids else pd.DataFrame()}
        
        self._worker = WorkerThread(_s)
        self._worker.finished.connect(self._on_legacy_search_done)
        self._worker.error.connect(self._on_error)
        self._worker.start()

    def _on_legacy_search_done(self, result):
        """Handle legacy search results"""
        self.progress.setVisible(False)
        self.search_btn.setEnabled(True)
        
        self._ids = result["ids"]
        self._summary_df = result["summary"]
        
        if not self._ids:
            self.status_lbl.setText("No results")
            QMessageBox.information(
                self,
                "No Results",
                "No results found.\n\n"
                "💡 Try using assembly-based search instead:\n"
                "• Enter organism name: Arabidopsis thaliana\n"
                "• Or assembly ID: GCF_000001735.4"
            )
            return
        
        df_to_table(self._summary_df, self.table)
        self.status_lbl.setText(f"Found {len(self._ids)} result(s) - Legacy mode")
        
        # Show legacy download options
        self._show_legacy_download_ui()

    def _show_legacy_download_ui(self):
        """Show old-style download for legacy search"""
        msg = (
            "⚠️ Legacy Search Mode\n\n"
            "You are using the old nucleotide search.\n"
            "GFF3 may not be available.\n\n"
            "For best results:\n"
            "• Use assembly IDs (GCF_)\n"
            "• Or organism names\n\n"
            "Continue with legacy download?"
        )
        
        reply = QMessageBox.question(
            self,
            "Legacy Mode",
            msg,
            QMessageBox.Yes | QMessageBox.No
        )
        
        if reply == QMessageBox.Yes:
            # Create legacy download dialog
            self._legacy_download_dialog()

    def _legacy_download_dialog(self):
        """Simplified legacy download"""
        QMessageBox.information(
            self,
            "Legacy Download",
            "Legacy nucleotide search is preserved but not recommended.\n\n"
            "Please use assembly-based search for reliable GFF3 access.\n\n"
            "Assembly-based features:\n"
            "✓ Complete genomes\n"
            "✓ GFF3\n"
            "✓ One-click download"
        )

    def _on_error(self, msg):
        """Handle errors"""
        self.progress.setVisible(False)
        self.dl_progress.setVisible(False)
        self.dl_status_lbl.setVisible(False)
        self.stop_btn.setVisible(False)
        self.stop_btn.setEnabled(True)
        self.dna_loader.stop()
        self.search_btn.setEnabled(True)
        self.download_btn.setEnabled(True)
        self.status_lbl.setText(f"Error: {msg}")
        QMessageBox.critical(self, "Error", msg)

