class Step1Tab(BackgroundWidget):
    def __init__(self):
        super().__init__()
        layout = QVBoxLayout(self)
        grp = QGroupBox("Inputs"); gl = QGridLayout(grp)

        gl.addWidget(QLabel("Genome FASTA:"), 0, 0)
