    def _browse_target(self):
        path = pick_file(self, "Target FASTA", "", "FASTA (*.fasta *.fa *.fna)")
        if path: self.target_edit.setText(path)

    def _do_run(self):
        target_path = self.target_edit.text().strip()
        if not target_path or not Path(target_path).exists():
            QMessageBox.warning(self, "Cis-GS", "Target FASTA not found."); return
        mtext = self.motif_edit.toPlainText().strip()
        if not mtext:
            QMessageBox.warning(self, "Cis-GS", "No motifs entered."); return
        motifs = parse_motif_lines(mtext)
        if not motifs:
            QMessageBox.warning(self, "Cis-GS", "Could not parse any motifs."); return
        self.progress.setVisible(True); self.run_btn.setEnabled(False)
        self.status_lbl.setText("Scanning …")
        self._worker = WorkerThread(scan_fasta_for_motifs, Path(target_path), motifs,
                                    self.iupac_cb.isChecked(), self.overlap_cb.isChecked(),
                                    self.revcomp_cb.isChecked(), self.context_spin.value())
        self._worker.finished.connect(self._on_done)
        self._worker.error.connect(self._on_error); self._worker.start()


    def _on_done(self, df):
        self.progress.setVisible(False)
        self.run_btn.setEnabled(True)
        self._df = df
        self._last_results = df
        
        if df.empty:
            self.status_lbl.setText("No hits found.")
            self.table.setRowCount(0)
            self.save_csv.setVisible(False)
            if hasattr(self, "_sig_table"):
                self._sig_table.setRowCount(0)
                if hasattr(self, "_sig_export_btn"):
                    self._sig_export_btn.setVisible(False)

            # Disable chromosome viz buttons
            if CHROMOSOME_UTILS_AVAILABLE:
                self.save_all_chr_btn.setEnabled(False)
                self.save_all_chr_svg_btn.setEnabled(False)
                self.save_single_chr_btn.setEnabled(False)
                self.chr_viz_preview.setText("No motif hits found")
        else:
            self.status_lbl.setText(f"Done. {len(df)} hit(s).")
            df_to_table(df.head(500), self.table)
            outdir = WORKSPACE / "custom_motif_search"
            safe_mkdir(outdir)
            df.to_csv(outdir / "motif_hits.csv", index=False)
            self.save_csv.setVisible(True)
            self._populate_sig_table(df)

            # Update chromosome visualization
            if CHROMOSOME_UTILS_AVAILABLE:
                self._update_chromosome_summary()
            
            # Enable chromosome viz buttons
            if CHROMOSOME_UTILS_AVAILABLE:
                self.save_all_chr_btn.setEnabled(True)
                self.save_all_chr_svg_btn.setEnabled(True)
                
                # Auto-generate preview
                self._preview_all_chromosomes()


    # ── Significance table helpers ────────────────────────────────────────

    def _build_sig_df(self, df):
        """One row per (gene, motif): best adj p-value + star rating."""
        if df.empty or "p_value_adj" not in df.columns:
            return pd.DataFrame()
        grp = (df.groupby(["gene_id","motif_name"], sort=False)
                 .agg(hits=("start_1based","count"),
                      p_adj=("p_value_adj","min"),
                      nlp=("neg_log10_p","max"))
                 .reset_index()
                 .sort_values("p_adj"))
        def _s(p):
            for t,s in [(1e-10,"★★★★★"),(1e-6,"★★★★"),(1e-4,"★★★"),(0.01,"★★"),(0.05,"★")]:
                if p <= t: return s
            return "ns"
        grp["Significance"] = grp["p_adj"].apply(_s)
        grp["p_adj_str"]    = grp["p_adj"].apply(
            lambda p: f"{p:.2e}" if p < 0.001 else f"{p:.4f}")
        grp["nlp"]          = grp["nlp"].round(2)
        out = grp[["gene_id","motif_name","hits","p_adj_str","nlp","Significance"]].copy()
        out.columns = ["Gene","Motif","Hits","p-value (adj)","−log₁₀(p)","Significance"]
        return out

    def _populate_sig_table(self, df):
        self._sig_df  = self._build_sig_df(df)
        self._full_df = df
        self._refresh_sig_table()

    def _refresh_sig_table(self):
        if not hasattr(self,"_sig_df") or self._sig_df.empty: return
        flt = self._sig_filter.currentText()
        thr_map = {
            "★  significant  (p ≤ 0.05)": 0.05,
            "★★  (p ≤ 0.01)":             0.01,
            "★★★  (p ≤ 1e-4)":            1e-4,
            "★★★★  (p ≤ 1e-6)":           1e-6,
            "★★★★★  (p ≤ 1e-10)":         1e-10,
        }
        sdf = self._sig_df.copy()
        if flt in thr_map and hasattr(self,"_full_df") and "p_value_adj" in self._full_df.columns:
            thr  = thr_map[flt]
            best = self._full_df.groupby(["gene_id","motif_name"])["p_value_adj"].min().reset_index()
            keep = set(zip(best.loc[best["p_value_adj"]<=thr,"gene_id"],
                           best.loc[best["p_value_adj"]<=thr,"motif_name"]))
            sdf  = sdf[sdf.apply(lambda r:(r["Gene"],r["Motif"]) in keep, axis=1)]

        df_to_table(sdf, self._sig_table)

        col_map = {"★★★★★":"#1B5E20","★★★★":"#2E7D32","★★★":"#388E3C",
                   "★★":"#558B2F","★":"#827717","ns":"#78909C"}
        sig_col = list(sdf.columns).index("Significance") if "Significance" in sdf.columns else -1
        if sig_col >= 0:
            for row in range(self._sig_table.rowCount()):
                item = self._sig_table.item(row, sig_col)
                if item:
                    item.setBackground(QColor(col_map.get(item.text(), "#546E7A")))
                    item.setForeground(QColor("white"))

        n = self._sig_table.rowCount()
        self._sig_export_btn.setVisible(n > 0)
        self._sig_export_btn.setText(f"💾 Export {n} rows …")

    def _browse_id_gff(self):
        """Browse for the GFF3 file used to resolve XM_/XP_ IDs."""
        # Auto-suggest last-used annotation directory
        start_dir = str(ANNOT_DIR) if ANNOT_DIR.exists() else str(WORKSPACE)
        current = self.id_gff_edit.text().strip()
        if current and Path(current).parent.exists():
            start_dir = str(Path(current).parent)
        path, _ = QFileDialog.getOpenFileName(
            self, "Select GFF3 Annotation", start_dir,
            "GFF3 Files (*.gff3 *.gff *.gff3.gz *.gff.gz);;All Files (*)")
        if path:
            self.id_gff_edit.setText(path)

    def _build_transcript_map(self):
        """Build and cache the gene→XM/XP map from the selected GFF3."""
        gff = self.id_gff_edit.text().strip()
        if not gff or not Path(gff).exists():
            return {}
        # Cache by file path so we don't re-parse on every save
        if getattr(self, "_id_map_source", None) == gff and hasattr(self, "_id_map"):
            return self._id_map
        try:
            self._id_map = build_transcript_map_from_gff3(gff)
            self._id_map_source = gff
            return self._id_map
        except Exception as e:
            QMessageBox.warning(self, "GFF3 Parse Error",
                f"Could not parse GFF3 for ID resolution:\n{e}")
            return {}

    def _resolve_ids(self, df):
        """Return a copy of df annotated / modified according to id_type_combo."""
        mode = self.id_type_combo.currentIndex()
        if mode == 0:          # LOC ID only – nothing to do
            return df

        tmap = self._build_transcript_map()
        if not tmap:
            QMessageBox.warning(self, "ID Resolution",
                "No GFF3 file provided or the file could not be parsed.\n"
                "Saving with original LOC IDs.")
            return df

        df = df.copy()

        def get_xm(gid):
            ids = tmap.get(_normalize_gene_id_for_map(str(gid)), {}).get("xm", [])
            return "; ".join(ids)

        def get_xp(gid):
            ids = tmap.get(_normalize_gene_id_for_map(str(gid)), {}).get("xp", [])
            return "; ".join(ids)

        if mode == 1:   # Add XM_ column
            df.insert(df.columns.get_loc("gene_id") + 1, "xm_ids",
                      df["gene_id"].apply(get_xm))
        elif mode == 2:  # Add XP_ column
            df.insert(df.columns.get_loc("gene_id") + 1, "xp_ids",
                      df["gene_id"].apply(get_xp))
        elif mode == 3:  # Add both
            pos = df.columns.get_loc("gene_id") + 1
            df.insert(pos,     "xm_ids", df["gene_id"].apply(get_xm))
            df.insert(pos + 1, "xp_ids", df["gene_id"].apply(get_xp))
        elif mode == 4:  # Replace with XM_
            df["gene_id"] = df["gene_id"].apply(
                lambda g: get_xm(g) or g)
        elif mode == 5:  # Replace with XP_
            df["gene_id"] = df["gene_id"].apply(
                lambda g: get_xp(g) or g)
        return df

    def _export_sig_csv(self):
        if not hasattr(self,"_sig_df") or self._sig_df.empty: return
        path, _ = QFileDialog.getSaveFileName(
            self, "Export Significance Table", "", "CSV (*.csv)")
        if path:
            out_df = self._resolve_ids(self._sig_df)
            out_df.to_csv(path, index=False)
            QMessageBox.information(self, "Cis-GS", f"Saved:\n{path}")

    def _save_csv(self):
        if self._df.empty: return
        path, _ = QFileDialog.getSaveFileName(self, "Save CSV", "", "CSV (*.csv)")
        if path:
            out_df = self._resolve_ids(self._df)
            out_df.to_csv(path, index=False)
            QMessageBox.information(self, "Cis-GS", f"Saved:\n{path}")

    def _on_error(self, msg):
        self.progress.setVisible(False); self.run_btn.setEnabled(True)
        self.status_lbl.setText(f"Error: {msg}")
        QMessageBox.critical(self, "Cis-GS", msg)

    def _update_chromosome_summary(self):
        """Update chromosome distribution summary"""
        if self._df.empty or not CHROMOSOME_UTILS_AVAILABLE:
            return
        
        if 'chromosome' in self._df.columns:
            chr_counts = self._df['chromosome'].value_counts()
            summary = "Chromosome distribution: " + " | ".join(
                [f"{chr}: {count} hits" for chr, count in chr_counts.head(10).items()]
            )
            if len(chr_counts) > 10:
                summary += f" | ...and {len(chr_counts)-10} more"
            
            self.chr_summary_label.setText(summary)
            
            # Update dropdown
            chromosomes = sorted(chr_counts.index.tolist())
            self.chr_select_combo.clear()
            self.chr_select_combo.addItems(chromosomes)
            
            # Enable buttons
            self.view_chr_btn.setEnabled(True)
            self.save_chr_btn.setEnabled(True)
