    def _preview_all_chromosomes(self):
        """Generate a preview showing all chromosomes overview"""
        if not CHROMOSOME_UTILS_AVAILABLE:
            return
        
        if self._df.empty:
            return
        
        try:
            # Create a simple summary view
            chr_counts = self._df['chromosome'].value_counts().sort_index()
            
            # Create a simple bar chart preview
            import matplotlib.pyplot as plt
            fig, ax = plt.subplots(figsize=(10, 6))
            chr_counts.plot(kind='bar', ax=ax, color='steelblue')
            ax.set_title('Motif Hits per Chromosome', fontsize=14, fontweight='bold')
            ax.set_xlabel('Chromosome', fontsize=12)
            ax.set_ylabel('Number of Hits', fontsize=12)
            ax.tick_params(axis='x', rotation=45)
            plt.tight_layout()
            
            # Save preview - Use cross-platform temp directory
            temp_dir = tempfile.gettempdir()
            temp_path = Path(temp_dir) / 'chr_overview.png'
            plt.savefig(temp_path, dpi=150, bbox_inches='tight')
            plt.close(fig)
            
            # Save path for later use
            self._current_preview_path = str(temp_path)
            
            # Load and display
            pixmap = QPixmap(str(temp_path))
            scaled_pixmap = pixmap.scaled(
                self.chr_viz_preview.width() - 20,
                self.chr_viz_preview.height() - 20,
                Qt.KeepAspectRatio,
                Qt.SmoothTransformation
            )
            self.chr_viz_preview.setPixmap(scaled_pixmap)
            
            # Enable save button
            self.save_single_chr_btn.setEnabled(True)
            
            self.status_lbl.setText(f"Overview ready: {len(chr_counts)} chromosomes")
            
        except Exception as e:
            print(f"Error generating overview: {e}")
            import traceback
            traceback.print_exc()
    
