# TAB 3: STEP 3 – Logo Builder
# ═══════════════════════════════════════════════════════════
class Step3Tab(BackgroundWidget):
    def __init__(self, step2_tab=None):
        super().__init__()
        self.step2_tab = step2_tab
        self._last_png = b""
        layout = QVBoxLayout(self)

        grp = QGroupBox("Logo Source"); gl = QVBoxLayout(grp)
        
