        load_btn_row = QHBoxLayout()
        load_btn = QPushButton("📥 Load Sequences from Motif Search (Step 2)")
        load_btn.clicked.connect(self._load_from_step2)
        load_btn.setToolTip("Load matched sequences from Step 2 results")
        load_btn.setStyleSheet("""
            QPushButton {
                background-color: #3498DB;
                color: white;
                font-size: 13px;
                font-weight: bold;
                padding: 8px 15px;
                border-radius: 4px;
                border: none;
            }
            QPushButton:hover { background-color: #2980B9; }
            QPushButton:pressed { background-color: #21618C; }
        """)
        load_btn_row.addWidget(load_btn)
