    def _update_status(self, message):
        """Update status text display"""
        timestamp = datetime.now().strftime("%H:%M:%S")
        self.status_text.append(f"[{timestamp}] {message}")
        QApplication.processEvents()
    
    def _normalize_gene_id(self, gid):
        """Normalize gene ID for matching"""
        gid = str(gid).strip()
        # Remove common prefixes
        for prefix in ('gene-', 'rna-', 'cds-', 'Gene:', 'GENE:'):
            if gid.lower().startswith(prefix.lower()):
                gid = gid[len(prefix):]
                break
        # Split on common separators and take first part
        for sep in ('|', ' ', '\t', ':', ';'):
            if sep in gid:
                gid = gid.split(sep)[0].strip()
                break
        return gid
    
    def _upload_motif_hits(self):
        """Upload motif hits CSV from Step 2"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Select Motif Hits CSV", 
            str(OUTPUTS_DIR), 
            "CSV Files (*.csv);;All Files (*)"
        )
        
        if not file_path:
            return
        
        try:
            self._update_status(f"Loading motif hits from {Path(file_path).name}...")
            df = _read_csv_robust(file_path, index_col=None)
            
            # Check if gene_id column exists
            if 'gene_id' not in df.columns:
                QMessageBox.warning(
                    self, "Format Error", 
                    "CSV must contain a 'gene_id' column.\n\n"
                    f"Found columns: {', '.join(df.columns)}"
                )
                return
            
            self.motif_hits_df = df
            n_genes = len(df['gene_id'].unique())
            
            self.motif_file_label.setText(Path(file_path).name)
            self.motif_file_label.setStyleSheet("padding: 5px; color: green; font-weight: bold;")
            
            self.motif_stats_label.setText(
                f"✅ Loaded: {len(df)} hits, {n_genes} unique genes"
            )
            
            self._update_status(f"✅ Loaded {n_genes} unique genes from motif hits")
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load motif hits:\n{e}")
            import traceback
            traceback.print_exc()
    
    def _upload_expression(self):
        """Upload whole organism expression CSV"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Select Expression CSV", 
            str(EXPR_DIR), 
            "CSV Files (*.csv);;All Files (*)"
        )
        
        if not file_path:
            return
        
        try:
            self._update_status(f"Loading expression data from {Path(file_path).name}...")
            df = _read_csv_robust(file_path, index_col=0)
            
            # Validate format
            if df.empty:
                QMessageBox.warning(self, "Format Error", "CSV file is empty!")
                return
            
            self.expression_df = df
            n_genes = len(df)
            n_samples = len(df.columns)
            
            self.expr_file_label.setText(Path(file_path).name)
            self.expr_file_label.setStyleSheet("padding: 5px; color: green; font-weight: bold;")
            
            self.expr_stats_label.setText(
                f"✅ Loaded: {n_genes} genes × {n_samples} samples"
            )
            
            self._update_status(f"✅ Loaded expression data: {n_genes} genes, {n_samples} samples")
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load expression data:\n{e}")
            import traceback
            traceback.print_exc()
    
    def _execute_matching(self):
        """Match motif hit genes with expression data and create filtered CSV"""
        if self.motif_hits_df is None:
            QMessageBox.warning(self, "Missing Data", "Please upload motif hits first!")
            return
        
        if self.expression_df is None:
            QMessageBox.warning(self, "Missing Data", "Please upload expression data first!")
            return
        
        try:
            self._update_status("Executing gene matching...")
            QApplication.processEvents()
            
            # Extract unique gene IDs from motif hits
            motif_genes = self.motif_hits_df['gene_id'].unique().tolist()
            motif_genes_normalized = {self._normalize_gene_id(g): g for g in motif_genes}
            
            # Normalize expression index
            expr_genes_normalized = {
                self._normalize_gene_id(g): g 
                for g in self.expression_df.index
            }
            
            # Find matches
            matched_genes = []
            matched_original = []
            
            for norm_id, orig_id in motif_genes_normalized.items():
                if norm_id in expr_genes_normalized:
                    matched_genes.append(expr_genes_normalized[norm_id])
                    matched_original.append(orig_id)
                else:
                    # Try stripping version suffix (e.g., .1, .2)
                    base_id = norm_id.rsplit('.', 1)[0]
                    if base_id in expr_genes_normalized:
                        matched_genes.append(expr_genes_normalized[base_id])
                        matched_original.append(orig_id)
            
            # Remove duplicates while preserving order
            matched_genes = list(dict.fromkeys(matched_genes))
            
            if not matched_genes:
                self.match_status_label.setText(
                    "❌ No matching genes found!\n\n"
                    f"Motif gene ID examples: {', '.join(list(motif_genes_normalized.keys())[:3])}\n"
                    f"Expression gene ID examples: {', '.join(list(expr_genes_normalized.keys())[:3])}\n\n"
                    "Check that both datasets use the same gene ID format."
                )
                self.match_status_label.setStyleSheet("padding: 10px; color: red;")
                return
            
            # Create filtered expression dataframe
            self.filtered_expr_df = self.expression_df.loc[matched_genes].copy()
            
            n_total_motif = len(motif_genes)
            n_matched = len(matched_genes)
            match_rate = (n_matched / n_total_motif) * 100
            
            self.match_status_label.setText(
                f"✅ Matching Complete!\n\n"
                f"• Total motif genes: {n_total_motif}\n"
                f"• Genes found in expression data: {n_matched}\n"
                f"• Match rate: {match_rate:.1f}%\n"
                f"• Filtered expression shape: {n_matched} genes × {len(self.filtered_expr_df.columns)} samples"
            )
            self.match_status_label.setStyleSheet("padding: 10px; color: green; font-weight: bold;")
            
            self._update_status(
                f"✅ Matched {n_matched}/{n_total_motif} genes ({match_rate:.1f}%)"
            )
            
            if match_rate < 50:
                QMessageBox.warning(
                    self, "Low Match Rate",
                    f"Only {match_rate:.1f}% of motif genes were found in expression data.\n\n"
                    "This may indicate:\n"
                    "• Different gene ID formats between datasets\n"
                    "• Incomplete expression data coverage\n\n"
                    "You can still download the filtered CSV, but verify your data sources."
                )
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Matching failed:\n{e}")
            import traceback
            traceback.print_exc()
    
    def _download_filtered_csv(self):
        """Download the filtered expression CSV"""
        if self.filtered_expr_df is None:
            QMessageBox.warning(
                self, "No Data", 
                "Please execute matching first!"
            )
            return
        
        # Suggest a filename
        default_name = f"filtered_expression_{datetime.now().strftime('%Y%m%d_%H%M%S')}.csv"
        
        save_path, _ = QFileDialog.getSaveFileName(
            self, "Save Filtered Expression CSV",
            str(OUTPUTS_DIR / default_name),
            "CSV Files (*.csv)"
        )
        
        if not save_path:
            return
        
        try:
            self.filtered_expr_df.to_csv(save_path)
            
            file_size = Path(save_path).stat().st_size / 1024  # KB
            
            self.download_status_label.setText(
                f"✅ Downloaded: {Path(save_path).name} ({file_size:.1f} KB)"
            )
            
            self._update_status(f"✅ Saved filtered CSV: {Path(save_path).name}")
            
            QMessageBox.information(
                self, "Download Complete",
                f"Filtered expression CSV saved successfully!\n\n"
                f"File: {Path(save_path).name}\n"
                f"Location: {Path(save_path).parent}\n"
                f"Size: {file_size:.1f} KB\n"
                f"Genes: {len(self.filtered_expr_df)}\n"
                f"Samples: {len(self.filtered_expr_df.columns)}\n\n"
                "✅ Use this file in the Coexpression and K-means Clustering tabs!"
            )
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to save CSV:\n{e}")
            import traceback
            traceback.print_exc()

