    def _normalize_data(self):
        if self._expr_df.empty:
            QMessageBox.warning(self, "Cis-GS", "Load data first."); return
        method = self.norm_combo.currentText()
        self.progress.setVisible(True); self.status_lbl.setText(f"Normalizing ({method}) …")
        self._worker = WorkerThread(normalize_expression_data, self._expr_df, method)
        self._worker.finished.connect(self._on_normalize_done)
        self._worker.error.connect(self._on_error); self._worker.start()

    def _on_normalize_done(self, ndf):
        self.progress.setVisible(False); self._expr_df = ndf
        self.status_lbl.setText(f"Normalized: {self._expr_df.shape}")
        self.results_text.setPlainText(f"Normalized:\n\n{self._expr_df.head()}")

    def _calculate_correlation(self):
        if self._expr_df.empty:
            QMessageBox.warning(self, "Cis-GS", "Load data first."); return
        method = self.corr_combo.currentText()
        self.progress.setVisible(True); self.status_lbl.setText(f"Computing correlation ({method}) …")
        self._worker = WorkerThread(calculate_correlation_matrix, self._expr_df, method)
        self._worker.finished.connect(self._on_correlation_done)
        self._worker.error.connect(self._on_error); self._worker.start()

    def _on_correlation_done(self, corr_matrix):
        self.progress.setVisible(False); self._corr_matrix = corr_matrix
        self.status_lbl.setText(f"Correlation matrix: {self._corr_matrix.shape}")
        self.results_text.setPlainText(f"Correlation:\n\n{self._corr_matrix.head()}")
        self.cluster_btn.setEnabled(True); self.export_corr_btn.setVisible(True)

    def _export_correlation(self):
        if self._corr_matrix.empty: return
        path, _ = QFileDialog.getSaveFileName(self, "Save Correlation CSV", "", "CSV (*.csv)")
        if path:
            self._corr_matrix.to_csv(path)
            QMessageBox.information(self, "Cis-GS", f"Saved:\n{path}")

    def _detect_modules(self):
        if self._corr_matrix.empty:
            QMessageBox.warning(self, "Cis-GS", "Calculate correlation first."); return
        threshold = self.threshold_spin.value()
        method    = self.cluster_combo.currentText()
        self.progress.setVisible(True); self.status_lbl.setText(f"Detecting modules ({method}) …")
        self._worker = WorkerThread(detect_coexpression_modules, self._corr_matrix, threshold, method)
        self._worker.finished.connect(self._on_modules_done)
        self._worker.error.connect(self._on_error); self._worker.start()

    def _on_modules_done(self, result):
        self.progress.setVisible(False)
        self._communities, self._network = result
        n_modules = len(set(self._communities.values()))
        self.status_lbl.setText(f"Found {n_modules} modules.")
        self.results_text.setPlainText(f"Modules detected: {n_modules}\n\n{str(self._communities)[:500]}")
        self.export_modules_btn.setVisible(True)

    def _export_modules(self):
        if not self._communities: return
        df = pd.DataFrame(list(self._communities.items()), columns=["gene_id", "module"])
        path, _ = QFileDialog.getSaveFileName(self, "Save Modules CSV", "", "CSV (*.csv)")
        if path:
            df.to_csv(path, index=False)
            QMessageBox.information(self, "Cis-GS", f"Saved:\n{path}")

