class _HelpSection(QWidget):
    """A collapsible accordion section for the Help tab."""
    def __init__(self, icon, title, html_body, parent=None):
        super().__init__(parent)
        self._open = False
        outer = QVBoxLayout(self); outer.setContentsMargins(0,0,0,4); outer.setSpacing(0)

        # Header button
        self._btn = QPushButton(f"  {icon}  {title}")
        self._btn.setCheckable(True)
        self._btn.setChecked(False)
        self._btn.setStyleSheet("""
            QPushButton {
                text-align: left; padding: 10px 14px;
                background: qlineargradient(x1:0,y1:0,x2:0,y2:1,stop:0 #e8f4f8,stop:1 #d0eaf3);
                border: 1px solid #b0d8e8; border-radius: 6px;
                font-size: 13px; font-weight: bold; color: #1a5276;
            }
            QPushButton:checked {
                background: qlineargradient(x1:0,y1:0,x2:0,y2:1,stop:0 #1a5276,stop:1 #2980b9);
                color: white; border-color: #1a5276;
            }
            QPushButton:hover:!checked { background: #c8e6f5; color: #1a5276; }
        """)
        self._btn.clicked.connect(self._toggle)
        outer.addWidget(self._btn)

        # Body
        self._body = QLabel(html_body)
        self._body.setWordWrap(True)
        self._body.setTextFormat(Qt.RichText)
        self._body.setOpenExternalLinks(True)
        self._body.setContentsMargins(16, 10, 16, 12)
        self._body.setStyleSheet(
            "background: white; border: 1px solid #b0d8e8; border-top: none;"
            "border-radius: 0 0 6px 6px; font-size: 12px; line-height: 1.6;"
            "color: #1a1a2e;"
        )
        self._body.setVisible(False)
        outer.addWidget(self._body)

    def _toggle(self, checked):
        self._body.setVisible(checked)
        arrow = "▲" if checked else "▼"
        txt = self._btn.text().split("  ", 2)
        # rebuild preserving icon and title
        self._btn.setText(self._btn.text())  # force repaint

    def expand(self):
        self._btn.setChecked(True); self._body.setVisible(True)

    def collapse(self):
        self._btn.setChecked(False); self._body.setVisible(False)


