# STEP 5: K-MEANS CLUSTERING ANALYSIS TAB
# ═══════════════════════════════════════════════════════════

class KMeansClusteringTab(BackgroundWidget):
    """
    K-means Expression Clustering Tab with Elbow Method
    Creates publication-quality plots with dendrograms, heatmaps, and line plots
    """
    def __init__(self):
        super().__init__()
