    def _load_expression(self):
        """Load expression matrix from CSV"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Load Expression Matrix", "", "CSV Files (*.csv);;TSV Files (*.tsv);;All Files (*)"
        )
        if not file_path:
            return
        
        try:
            # Read CSV/TSV with encoding fallback (handles µ, °, etc.)
            df = _read_csv_robust(file_path, index_col=0)
            
            if df.empty:
                QMessageBox.warning(self, "Error", "Expression file is empty!")
                return

            # ── Clean the data ────────────────────────────────────────────────
            # 1. Strip whitespace from column names and index
            df.columns = df.columns.str.strip()
            df.index   = df.index.astype(str).str.strip()

            # 2. Convert all values to numeric; '-', 'NA', 'N/A', '' → NaN
            df = df.apply(pd.to_numeric, errors='coerce')

            # 3. Drop columns that are entirely NaN
            df = df.dropna(axis=1, how='all')

            # 4. Handle genes with missing values:
            #    genes with ANY missing → fill with row mean
            #    (avoids discarding genes that have just one missing timepoint)
            row_means = df.mean(axis=1)
            for col in df.columns:
                mask = df[col].isna()
                if mask.any():
                    df.loc[mask, col] = row_means[mask]

            # 5. Drop any genes still all-NaN (e.g. entire row was missing)
            df = df.dropna(axis=0, how='all')

            # 6. Handle duplicate gene IDs — keep first occurrence
            n_before = len(df)
            df = df[~df.index.duplicated(keep='first')]
            n_dupes = n_before - len(df)

            # 7. Drop genes with zero variance (constant expression — useless for clustering)
            variances = df.var(axis=1)
            df = df[variances > 1e-12]
            n_zero_var = (variances <= 1e-12).sum()

            # ── Validate ──────────────────────────────────────────────────────
            if df.empty:
                QMessageBox.warning(self, "Error",
                    "No valid numeric expression data found after cleaning!")
                return
            
            numeric_cols = df.select_dtypes(include=[np.number]).columns
            if len(numeric_cols) == 0:
                QMessageBox.warning(self, "Error", "No numeric columns found!")
                return

            self.expr_df = df

            # Build informative status message
            notes = []
            if n_dupes > 0:
                notes.append(f"⚠️  {n_dupes} duplicate gene ID(s) removed (kept first)")
            if n_zero_var > 0:
                notes.append(f"⚠️  {n_zero_var} zero-variance gene(s) removed")
            notes_str = ("\n" + "\n".join(notes)) if notes else ""

            self.status_text.setPlainText(
                f"✅ Expression data loaded & cleaned!\n\n"
                f"Genes: {len(df)}\n"
                f"Samples: {len(df.columns)}\n"
                f"File: {Path(file_path).name}"
                f"{notes_str}"
            )
            
            self.data_info.setText(
                f"✅ Loaded: {len(df)} genes × {len(df.columns)} samples"
            )
            
            # Enable elbow button
            self.elbow_btn.setEnabled(True)
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load expression data:\n{str(e)}")
    
    def _run_elbow_method(self):
        """Run elbow method to determine optimal K"""
        if self.expr_df is None:
            QMessageBox.warning(self, "Warning", "Please load expression data first!")
            return
        
        try:
            self.status_text.setPlainText("⏳ Running elbow method analysis (K=2 to K=15)...")
            QApplication.processEvents()
            
            # Run elbow method
            self.elbow_result = elbow_method_kmeans(self.expr_df, max_k=15)
            
            optimal_k = self.elbow_result['optimal_k']
            
            # Display results
            self.elbow_result_label.setText(
                f"✅ Suggested Optimal K = {optimal_k}"
            )
            self.elbow_result_label.setStyleSheet("padding: 5px; font-weight: bold; color: green;")
            
            # Generate and display elbow plot
            plot_bytes = plot_elbow(self.elbow_result)
            pixmap = QPixmap()
            pixmap.loadFromData(QByteArray(plot_bytes))
            
            # Scale to fit
            scaled_pixmap = pixmap.scaled(
                self.elbow_plot_label.width() - 10,
                self.elbow_plot_label.maximumHeight() - 10,
                Qt.KeepAspectRatio,
                Qt.SmoothTransformation
            )
            self.elbow_plot_label.setPixmap(scaled_pixmap)
            
            # Enable "Use Suggested K" button
            self.use_suggested_k_btn.setEnabled(True)
            
            status_msg = f"✅ Elbow method analysis complete!\n\n"
            status_msg += f"Suggested optimal K: {optimal_k}\n"
            status_msg += f"K values tested: {min(self.elbow_result['k_values'])} to {max(self.elbow_result['k_values'])}\n\n"
            status_msg += "Click 'Use Suggested K' to apply this value, or manually set K in the parameters section."
            
            self.status_text.setPlainText(status_msg)
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Elbow method failed:\n{str(e)}")
            import traceback
            traceback.print_exc()
    
    def _use_suggested_k(self):
        """Apply the suggested K value from elbow method"""
        if self.elbow_result is None:
            QMessageBox.warning(self, "Warning", "Please run elbow method first!")
            return
        
        optimal_k = self.elbow_result['optimal_k']
        self.n_clusters_spin.setValue(optimal_k)
        
        QMessageBox.information(
            self, "K Value Updated",
            f"Number of clusters set to {optimal_k} (suggested by elbow method).\n\n"
            "You can now run K-means clustering with this value."
        )
    
    def _run_clustering(self):
        """Run k-means clustering — single run, consistent everywhere."""
        if self.expr_df is None:
            QMessageBox.warning(self, "Warning", "Please load expression data first!")
            return
        
        try:
            self.status_text.setPlainText("⏳ Running k-means clustering...")
            QApplication.processEvents()
            
            n_clusters  = self.n_clusters_spin.value()
            random_seed = self.random_seed_spin.value()
            max_iter    = self.max_iter_spin.value()

            # ── Single KMeans run — used for BOTH the plot and the CSV export ──
            self.kmeans_result = kmeans_temporal_clustering(
                self.expr_df,
                n_clusters=n_clusters,
                n_init=50,
                random_state=random_seed,
                max_iter=max_iter,
            )

            # cluster_labels: pandas Series (gene_name → cluster_id 0-based)
            # Stored as Series so gene↔cluster alignment is always preserved.
            self.cluster_labels = self.kmeans_result['cluster_labels']

            # Count genes per cluster (using the authoritative Series)
            cluster_counts = self.cluster_labels.value_counts().sort_index()

            status_msg  = "✅ K-means clustering completed!\n\n"
            status_msg += f"Number of clusters: {n_clusters}\n"
            status_msg += f"Total genes: {len(self.expr_df)}\n\n"
            status_msg += "Genes per cluster:\n"
            for cluster_id, count in cluster_counts.items():
                status_msg += f"  Cluster {cluster_id + 1}: {count} genes\n"

            self.status_text.setPlainText(status_msg)

        except Exception as e:
            QMessageBox.critical(self, "Error", f"Clustering failed:\n{str(e)}")
            import traceback
            traceback.print_exc()
    
    def _preview_plot(self):
        """Preview the cluster plot"""
        if not hasattr(self, 'kmeans_result'):
            QMessageBox.warning(self, "Warning", "Please run clustering first!")
            return
        
        try:
            self.status_text.setPlainText("⏳ Generating plot preview...")
            QApplication.processEvents()
            
            # Create plot and save to temp file for preview
            with tempfile.NamedTemporaryFile(suffix='.png', delete=False) as tmp:
                tmp_path = tmp.name
            
            plot_kmeans_spaghetti(
                self.expr_df,
                self.kmeans_result,
                output_path=tmp_path,
                show_gene_labels=self.show_gene_labels_check.isChecked()
            )
            
            # Open with system viewer
            import subprocess
            if sys.platform == 'win32':
                os.startfile(tmp_path)
            elif sys.platform == 'darwin':
                subprocess.run(['open', tmp_path])
            else:
                subprocess.run(['xdg-open', tmp_path])
            
            self.status_text.setPlainText("✅ Plot preview generated!")
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to generate plot:\n{str(e)}")
    
    def _export_plot(self):
        """Export the cluster plot"""
        if not hasattr(self, 'kmeans_result'):
            QMessageBox.warning(self, "Warning", "Please run clustering first!")
            return
        
        file_path, selected_filter = QFileDialog.getSaveFileName(
            self, "Export Plot", "kmeans_clusters.png",
            "PNG Image (*.png);;PDF Document (*.pdf);;SVG Image (*.svg)"
        )
        
        if not file_path:
            return
        
        try:
            self.status_text.setPlainText("⏳ Exporting plot...")
            QApplication.processEvents()
            
            plot_kmeans_spaghetti(
                self.expr_df,
                self.kmeans_result,
                output_path=file_path,
                show_gene_labels=self.show_gene_labels_check.isChecked()
            )
            
            self.status_text.setPlainText(f"✅ Plot exported to:\n{file_path}")
            QMessageBox.information(self, "Success", f"Plot saved to:\n{file_path}")
        
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to export plot:\n{str(e)}")
    
    def _export_elbow_plot(self):
        """Export the elbow plot"""
        if self.elbow_result is None:
            QMessageBox.warning(self, "Warning", "Please run elbow method first!")
            return
        
        file_path, _ = QFileDialog.getSaveFileName(
            self, "Export Elbow Plot", "elbow_plot.png",
            "PNG Image (*.png);;PDF Document (*.pdf);;SVG Image (*.svg)"
        )
        
        if not file_path:
            return
        
        try:
            plot_elbow(self.elbow_result, output_path=file_path)
            QMessageBox.information(self, "Success", f"Elbow plot saved to:\n{file_path}")
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to export elbow plot:\n{str(e)}")
    
    def _export_clusters(self):
        """Export cluster assignments to CSV"""
        if self.cluster_labels is None:
            QMessageBox.warning(self, "Warning", "Please run clustering first!")
            return
        
        file_path, _ = QFileDialog.getSaveFileName(
            self, "Export Cluster Assignments", "cluster_assignments.csv",
            "CSV Files (*.csv)"
        )
        
        if not file_path:
            return
        
        try:
            # Create dataframe with cluster assignments
            cluster_df = pd.DataFrame({
                'Gene': self.expr_df.index,
                'Cluster': self.cluster_labels + 1  # 1-indexed for readability
            })
            
            # Add expression data
            cluster_df = pd.concat([cluster_df, self.expr_df.reset_index(drop=True)], axis=1)
            
            cluster_df.to_csv(file_path, index=False)
            
            self.status_text.setPlainText(f"✅ Cluster assignments exported to:\n{file_path}")
            QMessageBox.information(self, "Success", f"Cluster assignments saved to:\n{file_path}")
        
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to export clusters:\n{str(e)}")
    
    def _export_all(self):
        """Export all results (plot + clusters + elbow)"""
        if self.cluster_labels is None:
            QMessageBox.warning(self, "Warning", "Please run clustering first!")
            return
        
        output_dir = QFileDialog.getExistingDirectory(self, "Select Output Directory")
        if not output_dir:
            return
        
        try:
            self.status_text.setPlainText("⏳ Exporting all results...")
            QApplication.processEvents()
            
            output_path = Path(output_dir)
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            
            # Export cluster plot
            plot_file = output_path / f"kmeans_clusters_{timestamp}.png"
            plot_kmeans_spaghetti(
                self.expr_df,
                self.kmeans_result,
                output_path=str(plot_file),
                show_gene_labels=self.show_gene_labels_check.isChecked()
            )
            
            # Export elbow plot if available
            elbow_file = None
            if self.elbow_result is not None:
                elbow_file = output_path / f"elbow_plot_{timestamp}.png"
                plot_elbow(self.elbow_result, output_path=str(elbow_file))
            
            # Export cluster assignments — use the Series so Gene↔Cluster alignment
            # is guaranteed even if expr_df row order differs from labels order
            lbl_series = self.cluster_labels  # Series: gene_name → 0-based cluster_id
            if not isinstance(lbl_series, pd.Series):
                lbl_series = pd.Series(lbl_series, index=self.expr_df.index)
            cluster_df = pd.DataFrame({
                'Gene':    lbl_series.index,
                'Cluster': lbl_series.values + 1,   # 1-based for export
            })
            cluster_df = pd.concat(
                [cluster_df.reset_index(drop=True),
                 self.expr_df.reindex(lbl_series.index).reset_index(drop=True)],
                axis=1
            )
            cluster_file = output_path / f"cluster_assignments_{timestamp}.csv"
            cluster_df.to_csv(cluster_file, index=False)
            
            # Export summary
            summary_file = output_path / f"cluster_summary_{timestamp}.txt"
            with open(summary_file, 'w') as f:
                f.write("K-means Clustering Summary\n")
                f.write("=" * 50 + "\n\n")
                f.write(f"Date: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
                f.write(f"Number of clusters: {self.n_clusters_spin.value()}\n")
                
                if self.elbow_result:
                    f.write(f"Suggested K (elbow method): {self.elbow_result['optimal_k']}\n")
                
                f.write(f"Total genes: {len(self.expr_df)}\n")
                f.write(f"Total samples: {len(self.expr_df.columns)}\n\n")
                
                lbl = self.cluster_labels
                if not isinstance(lbl, pd.Series):
                    lbl = pd.Series(lbl)
                cluster_counts = lbl.value_counts().sort_index()
                f.write("Genes per cluster:\n")
                for cluster_id, count in cluster_counts.items():
                    f.write(f"  Cluster {cluster_id + 1}: {count} genes\n")
            
            msg = f"✅ All results exported to:\n{output_dir}\n\n"
            msg += f"Files created:\n"
            msg += f"  - {plot_file.name}\n"
            if elbow_file:
                msg += f"  - {elbow_file.name}\n"
            msg += f"  - {cluster_file.name}\n"
            msg += f"  - {summary_file.name}"
            
            self.status_text.setPlainText(msg)
            QMessageBox.information(self, "Success", msg)
        
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to export results:\n{str(e)}")


