        super().__init__()
        self.setWindowTitle("Cis-GS: Cis-regulatory Element Genome Scanner")

        # Set window icon from app logo
        _icon_pix = QPixmap()
        _icon_pix.loadFromData(__import__("base64").b64decode(APP_ICON_B64))
        self.setWindowIcon(QIcon(_icon_pix))
        self.setGeometry(100, 100, 1400, 900)
        
        # Create central widget with tabs
        central = QWidget()
        self.setCentralWidget(central)
        layout = QVBoxLayout(central)
        
        # Create tab widget
        self.tabs = QTabWidget()
        self.tabs.setDocumentMode(True)
        
        # Add all tabs - save references for cross-tab communication
        self.tabs.addTab(NCBITab(), "🧬 NCBI Fetch")
        self.tabs.addTab(Step1Tab(), "📋 Step 1: Promoters")
        
        # Save Step2 reference
        self.step2_tab = Step2Tab()
        self.tabs.addTab(self.step2_tab, "🔍 Step 2: Motif Search")
        
        # Pass Step2 to Step3
        self.step3_tab = Step3Tab(step2_tab=self.step2_tab)
