def main():
    app = QApplication(sys.argv)
    app.setStyle("Fusion")

    # Set app icon — appears in taskbar, alt-tab, and window title bar
    import base64 as _b64
    _app_icon_pix = QPixmap()
    _app_icon_pix.loadFromData(_b64.b64decode(APP_ICON_B64))
    _app_icon = QIcon(_app_icon_pix)
    app.setWindowIcon(_app_icon)

    # Initialize workspace first (needed for theme persistence)
    ensure_dirs()
    theme_mgr.init_file(WORKSPACE)
    
    # Apply saved theme
    theme_mgr.apply(app)
    
    win = MainWindow()
    win.show()
    sys.exit(app.exec_())

if __name__ == "__main__":
    main()
